PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?anime ?animeLabel
WHERE {
  wd:Q21637 wdt:P127 ?company .
  ?anime wdt:P127 ?company .
  ?anime wdt:P31 wd:Q11424 .
  OPTIONAL { ?anime rdfs:label ?animeLabel . FILTER (LANG(?animeLabel) = "en") }
}

